 38	// LLMProvider configures a single LLM provider.
 39	type LLMProvider struct {
 40		// Name is a unique identifier for this provider configuration.
 41		Name string `toml:"name"`
 42		// API specifies which API style to use (anthropic-messages, openai-completions, openai-responses).
 43		API string `toml:"api"`
 44		// BaseURL is the API endpoint.
 45		BaseURL string `toml:"base-url"`
 46		// APIKeyCommand is a command to run to get the API key. If empty, no auth is used.
 47		APIKeyCommand string `toml:"api-key-command"`
 48		// Models lists the model IDs available through this provider.
 49		Models []string `toml:"models"`
 50	}
