 77	// Load loads configuration from the repo root and the global config file.
 78	// Returns an empty config if no config files exist.
 79	func Load(repoPath string) (*Config, error) {
 80		globalPath, err := globalConfigPath()
 81		if err != nil {
 82			return nil, err
 83		}
 84	
 85		globalCfg, globalMeta, err := loadConfigFile(globalPath)
 86		if err != nil {
 87			return nil, err
 88		}
 89	
 90		projectCfg, projectMeta, err := loadProjectConfig(repoPath)
 91		if err != nil {
 92			return nil, err
 93		}
 94	
 95		merged := mergeConfigs(globalCfg, projectCfg, globalMeta, projectMeta)
 96		return merged, nil
 97	}
