111	func loadProjectConfig(repoPath string) (*Config, toml.MetaData, error) {
112		rootPath := filepath.Join(repoPath, "incrementum.toml")
113		altPath := filepath.Join(repoPath, ".incrementum", "config.toml")
114	
115		rootExists, err := fileExists(rootPath)
116		if err != nil {
117			return nil, toml.MetaData{}, fmt.Errorf("check project config %s: %w", rootPath, err)
118		}
119	
120		altExists, err := fileExists(altPath)
121		if err != nil {
122			return nil, toml.MetaData{}, fmt.Errorf("check project config %s: %w", altPath, err)
123		}
124	
125		if rootExists && altExists {
126			return nil, toml.MetaData{}, fmt.Errorf("project config files both exist: %s and %s", rootPath, altPath)
127		}
128	
129		if rootExists {
130			return loadConfigFile(rootPath)
131		}
132		if altExists {
133			return loadConfigFile(altPath)
134		}
135	
136		return &Config{}, toml.MetaData{}, nil
137	}
