158	func loadConfigFile(path string) (*Config, toml.MetaData, error) {
159		data, err := os.ReadFile(path)
160		if os.IsNotExist(err) {
161			return &Config{}, toml.MetaData{}, nil
162		}
163		if err != nil {
164			return nil, toml.MetaData{}, fmt.Errorf("read config file %s: %w", path, err)
165		}
166	
167		var cfg Config
168		meta, err := toml.Decode(string(data), &cfg)
169		if err != nil {
170			return nil, toml.MetaData{}, fmt.Errorf("parse config file %s: %w", path, err)
171		}
172	
173		return &cfg, meta, nil
174	}
