176	func mergeConfigs(globalCfg, projectCfg *Config, globalMeta, projectMeta toml.MetaData) *Config {
177		if globalCfg == nil {
178			globalCfg = &Config{}
179		}
180		if projectCfg == nil {
181			projectCfg = &Config{}
182		}
183	
184		merged := Config{}
185		merged.Workspace.OnCreate = mergeString(projectMeta.IsDefined("workspace", "on-create"), projectCfg.Workspace.OnCreate, globalCfg.Workspace.OnCreate)
186		merged.Workspace.OnAcquire = mergeString(projectMeta.IsDefined("workspace", "on-acquire"), projectCfg.Workspace.OnAcquire, globalCfg.Workspace.OnAcquire)
187		merged.Job.Model = mergeString(projectMeta.IsDefined("job", "model"), projectCfg.Job.Model, globalCfg.Job.Model)
188		merged.Job.ImplementationModel = mergeString(projectMeta.IsDefined("job", "implementation-model"), projectCfg.Job.ImplementationModel, globalCfg.Job.ImplementationModel)
189		merged.Job.CodeReviewModel = mergeString(projectMeta.IsDefined("job", "code-review-model"), projectCfg.Job.CodeReviewModel, globalCfg.Job.CodeReviewModel)
190		merged.Job.ProjectReviewModel = mergeString(projectMeta.IsDefined("job", "project-review-model"), projectCfg.Job.ProjectReviewModel, globalCfg.Job.ProjectReviewModel)
191		if projectMeta.IsDefined("job", "test-commands") {
192			merged.Job.TestCommands = append([]string(nil), projectCfg.Job.TestCommands...)
193		} else if globalMeta.IsDefined("job", "test-commands") {
194			merged.Job.TestCommands = append([]string(nil), globalCfg.Job.TestCommands...)
195		}
196	
197		// Merge LLM config
198		merged.LLM.Providers = mergeLLMProviders(globalCfg.LLM.Providers, projectCfg.LLM.Providers)
199		merged.LLM.Model = mergeString(projectMeta.IsDefined("llm", "model"), projectCfg.LLM.Model, globalCfg.LLM.Model)
200	
201		// Merge Agent config
202		merged.Agent.Model = mergeString(projectMeta.IsDefined("agent", "model"), projectCfg.Agent.Model, globalCfg.Agent.Model)
203	
204		return &merged
205	}
