207	// mergeLLMProviders merges global and project LLM providers.
208	// Project providers with the same name as global providers override them.
209	// Providers are returned in order: project providers first, then remaining global providers.
210	func mergeLLMProviders(global, project []LLMProvider) []LLMProvider {
211		if len(project) == 0 && len(global) == 0 {
212			return nil
213		}
214	
215		// Build a set of project provider names for quick lookup
216		projectNames := make(map[string]bool, len(project))
217		for _, p := range project {
218			projectNames[p.Name] = true
219		}
220	
221		// Start with project providers

221		// Start with project providers
222		result := make([]LLMProvider, 0, len(project)+len(global))
223		result = append(result, project...)
224	
225		// Add global providers that aren't overridden by project
226		for _, p := range global {
227			if !projectNames[p.Name] {
228				result = append(result, p)
229			}
230		}
231	
232		return result
233	}
