243	// RunScript executes a script in the given directory.
244	// If the script starts with a shebang (#!), that interpreter is used.
245	// Otherwise, the script is run with /bin/bash.
246	func RunScript(dir, script string) error {
247		script = internalstrings.TrimSpace(script)
248		if script == "" {
249			return nil
250		}
251	
252		var interpreter string
253		scriptBody := ""
254	
255		if strings.HasPrefix(script, "#!") {
256			// Extract shebang line
257			lines := strings.SplitN(script, "\n", 2)
258			interpreter = internalstrings.TrimSpace(strings.TrimPrefix(lines[0], "#!"))
259			if len(lines) > 1 {
260				scriptBody = lines[1]
261			}
262		} else {
263			interpreter = "/bin/bash"
264			scriptBody = script
265		}
266	
267		// Parse interpreter and args (e.g., "/usr/bin/env python3" or "/bin/bash -e")
268		parts := strings.Fields(interpreter)
269		if len(parts) == 0 {
270			return fmt.Errorf("empty interpreter in shebang")
271		}
272	
273		cmd := exec.Command(parts[0], parts[1:]...)
274		cmd.Dir = dir
275		cmd.Stdin = strings.NewReader(scriptBody)
276		cmd.Stdout = os.Stdout
277		cmd.Stderr = os.Stderr
