924		case ReviewOutcomeAbandon:
925			status := StatusAbandoned
926			updated, err = manager.Update(updated.ID, UpdateOptions{Status: &status}, opts.Now())
927			if err != nil {
928				return ReviewingStageResult{}, err
929			}
