55			fmt.Fprintf(&builder, "%s\n", template.Name)
56			fmt.Fprintf(&builder, "  Override: %s\n", job.PromptOverridePath(template.Name))
57			builder.WriteString("  Variables:\n")
58			for _, variable := range template.Variables {
59				fmt.Fprintf(&builder, "    - %s (%s)\n", variable.Name, variable.Type)
60			}
61			builder.WriteString("  Template:\n")
62			builder.WriteString("```\n")
63			builder.WriteString(template.Contents)
64			if !strings.HasSuffix(template.Contents, "\n") {
65				builder.WriteString("\n")
66			}
67			builder.WriteString("```\n")
68		}
69		_, err = fmt.Fprint(cmd.OutOrStdout(), builder.String())
70		return err
